mapper.select:
select id, conversation_id, user_id, role, status, unread_count, is_muted, is_pinned,
       last_read_message_id, joined_at, created_at, updated_at
from cook_conversation_members
where conversation_id = #{conversationId}
  and user_id = #{userId}
limit 1

mapper.update:
update cook_conversation_members
set unread_count = unread_count + 1,
    updated_at = current_timestamp
where conversation_id = #{conversationId}
  and user_id <> #{senderId}
  and status = 'normal'
